 41	typedef enum {
 42	 NEW_TRANSMISSION_HARQ,
 43	 RETRANSMISSION_HARQ
 44	} harq_result_t;
 45	
 46	typedef struct {
 47	  /// HARQ tx status
 48	  harq_result_t tx_status;
 49	  /// Status Flag indicating for this ULSCH (idle,active,disabled)
 50	  SCH_status_t ULstatus;
 51	  /// Last TPC command
 52	  uint8_t TPC;
 53	  /// Length of ACK information (bits)
 54	  uint8_t O_ACK;
 55	  /// Index of current HARQ round for this ULSCH
 56	  uint8_t round;
 57	  /// pointer to pdu from MAC interface (TS 36.212 V15.4.0, Sec 5.1 p. 8)
 58	  unsigned char *payload_AB;
 59	  /// Pointers to transport block segments
 60	  uint8_t **c;
 61	  /// LDPC-code outputs
 62	  uint8_t **d;
 63	  /// LDPC-code outputs (TS 36.212 V15.4.0, Sec 5.3.2 p. 17)
 64	  uint8_t *e;
 65	  /// Rate matching (Interleaving) outputs (TS 36.212 V15.4.0, Sec 5.4.2.2 p. 30)
 66	  uint8_t *f;
 67	  /// Number of code segments
 68	  uint32_t C;
 69	  /// Number of bits in code segments
 70	  uint32_t K;
 71	  /// Total number of bits across all segments
 72	  uint32_t sumKr;
 73	  /// Number of "Filler" bits
 74	  uint32_t F;
 75	  /// n_DMRS  for cyclic shift of DMRS
 76	  uint8_t n_DMRS;
 77	  /// n_DMRS2 for cyclic shift of DMRS
 78	  uint8_t n_DMRS2;
 79	  /// Number of soft channel bits
 80	  uint32_t G;
 81	  // Number of modulated symbols carrying data
 82	  uint32_t num_of_mod_symbols;
 83	  // Encoder BG
 84	  uint8_t BG;
 85	  // LDPC lifting size
 86	  uint32_t Z;
 87	} NR_UL_UE_HARQ_t;
 88	
 89	typedef struct {
 90	  /// NDAPI struct for UE
 91	  nfapi_nr_ue_pusch_pdu_t pusch_pdu;
 92	  // UL number of harq processes
 93	  uint8_t number_harq_processes_for_pusch;
 94	  /// RNTI type
 95	  nr_rnti_type_t rnti_type;
 96	  /// Cell ID
 97	  int     Nid_cell;
 98	  /// bit mask of PT-RS ofdm symbol indicies
 99	  uint16_t ptrs_symbols;
100	} NR_UE_ULSCH_t;
101	
102	typedef struct {
103	  /// Indicator of first reception
104	  uint8_t first_rx;
105	  /// DLSCH status flag indicating
106	  SCH_status_t status;
107	  /// Pointers to transport block segments
108	  uint8_t **c;
109	  /// soft bits for each received segment ("d"-sequence)(for definition see 36-212 V8.6 2009-03, p.15)
110	  /// Accumulates the soft bits for each round to increase decoding success (HARQ)
111	  int16_t **d;
112	  /// Index of current HARQ round for this DLSCH
113	  uint8_t DLround;
114	  /// Number of code segments 
115	  uint32_t C;
116	  /// Number of bits in code segments
117	  uint32_t K;
118	  /// Number of "Filler" bits 
119	  uint32_t F;
120	  /// LDPC lifting factor
121	  uint32_t Z;
122	  /// codeword this transport block is mapped to
123	  uint8_t codeword;
124	  /// HARQ-ACKs
125	  bool decodeResult;
126	  /// Last index of LLR buffer that contains information.
127	  /// Used for computing LDPC decoder R
128	  int llrLen;
129	  decode_abort_t abort_decode;
130	} NR_DL_UE_HARQ_t;
131	
132	typedef struct {
133	  /// RNTI
134	  uint16_t rnti;
135	  /// RNTI type
136	  uint8_t rnti_type;
137	  /// Active flag for DLSCH demodulation
138	  bool active;
139	  /// Structure to hold dlsch config from MAC
140	  fapi_nr_dl_config_dlsch_pdu_rel15_t dlsch_config;
141	  /// Number of MIMO layers (streams) 
142	  uint8_t Nl;
143	  /// Maximum number of LDPC iterations
144	  uint8_t max_ldpc_iterations;
145	  /// number of iterations used in last turbo decoding
146	  uint8_t last_iteration_cnt;
147	  /// bit mask of PT-RS ofdm symbol indicies
148	  uint16_t ptrs_symbols;
149	  // PTRS symbol index, to be updated every PTRS symbol within a slot.
150	  uint8_t ptrs_symbol_index;
151	} NR_UE_DLSCH_t;
152	#endif

