   141	void init_nr_prs_ue_vars(PHY_VARS_NR_UE *ue)
   142	{
   143	  NR_UE_PRS   **const prs_vars = ue->prs_vars;
   144	  NR_DL_FRAME_PARMS *const fp  = &ue->frame_parms;
   145	
   146	  // PRS vars init
   147	  for(int idx = 0; idx < NR_MAX_PRS_COMB_SIZE; idx++)
   148	  {
   149	    prs_vars[idx] = malloc16_clear(sizeof(NR_UE_PRS));
   150	    // PRS channel estimates
   151	
   152	    for(int k = 0; k < NR_MAX_PRS_RESOURCES_PER_SET; k++)
   153	    {
   154	      prs_vars[idx]->prs_resource[k].prs_meas = malloc16_clear(fp->nb_antennas_rx * sizeof(prs_meas_t *));
   155	      AssertFatal((prs_vars[idx]->prs_resource[k].prs_meas!=NULL), "%s: PRS measurements malloc failed for gNB_id %d\n", __FUNCTION__, idx);
   156	
   157	      for (int j=0; j<fp->nb_antennas_rx; j++) {
   158	        prs_vars[idx]->prs_resource[k].prs_meas[j] = malloc16_clear(sizeof(prs_meas_t));
   159	        AssertFatal((prs_vars[idx]->prs_resource[k].prs_meas[j]!=NULL), "%s: PRS measurements malloc failed for gNB_id %d, rx_ant %d\n", __FUNCTION__, idx, j);
   160	      }
   161	    }
   162	  }
   163	
   164	  // load the config file params
   165	  RCconfig_nrUE_prs(ue);
   166	}
